// /frontend/src/components/Forecast.jsx
import React from "react";

function row(day, i) {
  const dt = day?.dt ? new Date(day.dt * 1000) : new Date(Date.now() + (i + 1) * 86400_000);
  const wday = dt.toLocaleDateString([], { weekday: "short" });
  const hi = Math.round(day?.temp?.max ?? day?.max ?? 0);
  const lo = Math.round(day?.temp?.min ?? day?.min ?? 0);
  const desc = day?.weather?.[0]?.description ?? day?.summary ?? "";
  return (
    <div
      key={i}
      className="flex items-center justify-between px-4 py-3 rounded-xl bg-white/5"
    >
      <div className="w-16 opacity-80">{wday}</div>
      <div className="flex-1 truncate px-2 capitalize opacity-80">{desc}</div>
      <div className="w-24 text-right">
        <span className="opacity-80">{hi}°</span>
        <span className="opacity-60 ml-2">{lo}°</span>
      </div>
    </div>
  );
}

export default function Forecast({ daily = [] }) {
  const days = Array.isArray(daily) ? daily.slice(0, 16) : [];

  return (
    <div className="rounded-2xl backdrop-blur-xl bg-black/40 ring-1 ring-white/10 p-3">
      {/* Mobile: horizontal cards that you can swipe (Apple-like), Desktop: 2-col grid */}
      <div className="md:hidden flex gap-3 overflow-x-auto snap-x snap-mandatory">
        {days.map((d, i) => (
          <div key={i} className="min-w-[80%] snap-start">{row(d, i)}</div>
        ))}
      </div>

      <div className="hidden md:grid md:grid-cols-2 md:gap-3">
        {days.map((d, i) => row(d, i))}
      </div>
    </div>
  );
}
